import * as React from 'react';
import { cn } from '@/lib/utils';
import { Slot as ReactSlot, Slottable } from '@radix-ui/react-slot';
import { cva, type VariantProps } from 'class-variance-authority';

type Slot = { icon: React.ElementType } | { custom: React.ReactNode };

const buttonVariants = cva(
  'inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium ring-offset-[var(--ring-offset)] transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-[var(--ring)] focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0',
  {
    variants: {
      variant: {
        default: 'bg-[var(--primary-brand)] text-[var(--primary-foreground)] hover:opacity-90',
        destructive: 'bg-[var(--destructive)] text-[var(--destructive-foreground)] hover:opacity-90',
        outline: 'border border-[var(--input)] bg-[var(--background)] hover:bg-[var(--accent)] hover:text-[var(--accent-foreground)]',
        secondary: 'bg-[var(--secondary)] text-[var(--secondary-foreground)] hover:opacity-80',
        ghost: 'hover:bg-[var(--accent)] hover:text-[var(--accent-foreground)]',
        link: 'text-[var(--primary)] underline-offset-4 hover:underline',
        defaultOutline: 'border border-[var(--primary-brand)] bg-[var(--background)] text-[var(--primary-brand)] hover:opacity-90',
      },
      size: {
        default: 'h-10 px-4 py-2',
        xs: 'h-8 rounded-md px-2.5',
        sm: 'h-9 rounded-md px-3',
        lg: 'h-11 rounded-md px-8',
        icon: 'size-10',
      },
    },
    defaultVariants: {
      variant: 'default',
      size: 'default',
    },
  },
);

const iconVariants = cva('size-4', {
  variants: {
    variant: {
      default: 'text-[var(--primary-foreground)]',
      destructive: 'text-[var(--destructive-foreground)]',
      outline: 'text-[var(--foreground)]',
      secondary: 'text-[var(--secondary-foreground)]',
      ghost: 'text-[var(--accent-foreground)]',
      link: 'text-[var(--primary)]',
      defaultOutline: 'text-[var(--primary-brand)]',
    },
  },
  defaultVariants: {
    variant: 'default',
  },
});

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
  left?: Slot;
  right?: Slot;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, children, variant, size, asChild = false, left, right, ...props }, ref) => {
    const Comp = asChild ? ReactSlot : 'button';
    const renderSlot = (slot: Slot): React.ReactNode => {
      if ('custom' in slot) return slot.custom;
      if ('icon' in slot) return <slot.icon className={cn(iconVariants({ variant }))} />;
      return null;
    };
    return (
      <Comp className={cn(buttonVariants({ variant, size, className }))} ref={ref} {...props}>
        {left && renderSlot(left)}
        {asChild ? <Slottable>{children}</Slottable> : children}
        {right && renderSlot(right)}
      </Comp>
    );
  },
);
Button.displayName = 'Button';

export { Button, buttonVariants };
